import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.BKG_UbFK.js";const p=JSON.parse('{"title":"مقدمة","description":"","frontmatter":{},"headers":[],"relativePath":"ar/guide/introduction.md","filePath":"ar/guide/introduction.md"}'),d={name:"ar/guide/introduction.md"};function i(l,e,c,s,n,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="مقدمة" tabindex="-1">مقدمة <a class="header-anchor" href="#مقدمة" aria-label="Permalink to &quot;مقدمة&quot;">​</a></h1><h2 id="ما-هو-clearance؟" tabindex="-1">ما هو Clearance؟ <a class="header-anchor" href="#ما-هو-clearance؟" aria-label="Permalink to &quot;ما هو Clearance؟&quot;">​</a></h2><p>Clearance هي لوحة تحكم جاهزة للتركيب في تطبيقات Laravel، مبنية فوق <a href="https://github.com/spatie/laravel-permission" target="_blank" rel="noreferrer">spatie/laravel-permission</a>. تضيف لوحة Livewire 4 + Flux UI لإدارة الصلاحيات والأدوار والحراس والإعدادات، بالإضافة إلى طبقة تفويض سياقي وأسقف للأدوار (role ceilings) - قابلة للتثبيت بأمر artisan واحد، دون تعديل أي جدول من جداول Spatie.</p><p>يمنحك Clearance:</p><ul><li><strong>لوحة تحكم</strong> للصلاحيات والأدوار والحراس والإعدادات ولوحة قيادة - استخدم المسارات (routes) الجاهزة أو ضمّن كل مكوّن Livewire على حدة.</li><li><strong>تفويض سياقي</strong> - امنح دوراً أو صلاحية مقيّدة بنسخة نموذج (model instance) محددة (متجر، مستأجر، مشروع)، عبر <code>$user-&gt;canIn()</code>، وتوجيهات Blade من نوع <code>@canin</code>/<code>@hasrolein</code>، وعبر <code>ContextService</code> للاستخدام خارج نموذج User.</li><li><strong>أدوار سقفية (Ceiling roles)</strong> - يمكن لدور ما أن يعلن عن دور أب تُشكّل مجموعة صلاحياته حداً أعلى؛ لا يمكن لدور فرعي أن يتجاوز أبداً حدود دوره الأب، ويُفرض ذلك تلقائياً عند كل حفظ.</li><li><strong>صلاحيات كتابة دقيقة التحكم</strong> - صلاحية واحدة قابلة للتفويض من نوع <code>clearance-{section}-write</code> لكل قسم من أقسام اللوحة، بحيث يمكنك منح &quot;إدارة الأدوار&quot; دون أن تمنح معها &quot;إدارة الإعدادات.&quot;</li><li><strong>مشرف فائق (Super Admin)</strong> مع تجاوز شامل (Gate bypass) اختياري، وكشف تلقائي للأدوار المشابهة للمشرف الموجودة مسبقاً، وترقية آمنة وغير هدّامة.</li><li><strong>وحدة المستخدمين</strong> (اختيارية) - عيّن الأدوار عالمياً أو ضمن سياق محدد، مع تجاوزات صلاحيات لكل سياق، من لوحة خاصة بكل مستخدم.</li><li><strong>لوحة الإعدادات</strong> - اسم عرض ووصف وأيقونة SVG معقّمة ولون لكل دور/حارس؛ دور افتراضي قابل للتهيئة مع تعيين تلقائي وتعيين جماعي.</li><li><strong>إدارة الحراس</strong> - حراس مخزّنون في قاعدة البيانات، تُحقن في <code>auth.guards</code> عند الإقلاع، ومقيّدة بمجموعة محركات (drivers) مسموح بها.</li><li><strong>9 لغات مرفقة</strong> (ar، en، es، fr، hi، it، pt، ru، zh)، مُختبرة لتطابق المفاتيح.</li><li><strong>نقاط توسّع</strong> - trait من نوع <code>HasClearance</code>، وtrait من نوع <code>HasPermissionGroups</code>، وعقد (contract) <code>ClearanceContextable</code>، ومكوّنات Blade قابلة لإعادة الاستخدام.</li><li><strong>تعقيم SVG</strong> - كل أيقونة يقدّمها المستخدم تمر عبر مُعقِّم بقائمة سماح قبل التخزين وعند العرض.</li><li><strong>مُحصّنة أمنياً</strong> - حدود سقفية لمنع تصعيد الصلاحيات على كل مسار يمنح صلاحية، وتجاوزات سياقية ذات أولوية للرفض، ومساحة أسماء <code>clearance-*</code> محمية. انظر <a href="/clearance-docs/ar/guide/security.html">الأمان</a>.</li></ul><h2 id="العلاقة-مع-spatie-laravel-permission" tabindex="-1">العلاقة مع spatie/laravel-permission <a class="header-anchor" href="#العلاقة-مع-spatie-laravel-permission" aria-label="Permalink to &quot;العلاقة مع spatie/laravel-permission&quot;">​</a></h2><p>Clearance ليست بديلاً لحزمة صلاحيات Spatie - إنها طبقة واجهة وتفويض فوقها. لا تزال الأدوار والصلاحيات هي نماذج <code>Role</code> و<code>Permission</code> الخاصة بـ Spatie، ولا تزال مخزّنة في جداول Spatie: <code>roles</code>، و<code>permissions</code>، و<code>model_has_roles</code>، و<code>model_has_permissions</code>، و<code>role_has_permissions</code>. لا تُعدّل Clearance تلك الجداول أبداً. كل ما تضيفه Clearance - بيانات العرض الوصفية، ونطاق الدور، والأسقف، والتعيينات السياقية، والتجاوزات الخاصة بكل سياق - يعيش في مجموعة جداول خاصة بها باسم <code>clr_*</code>. انظر <a href="/clearance-docs/ar/guide/architecture.html">البنية المعمارية</a> للاطلاع على التفصيل الكامل.</p><h2 id="المتطلبات" tabindex="-1">المتطلبات <a class="header-anchor" href="#المتطلبات" aria-label="Permalink to &quot;المتطلبات&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الاعتمادية</th><th>الإصدار</th></tr></thead><tbody><tr><td>PHP</td><td>^8.3</td></tr><tr><td>Laravel</td><td>^11.0 | ^12.0 | ^13.0</td></tr><tr><td>spatie/laravel-permission</td><td>^6.0</td></tr><tr><td>livewire/livewire</td><td>^3.0 | ^4.0</td></tr><tr><td>livewire/flux</td><td>^2.14</td></tr></tbody></table><h2 id="مفاهيم-أساسية" tabindex="-1">مفاهيم أساسية <a class="header-anchor" href="#مفاهيم-أساسية" aria-label="Permalink to &quot;مفاهيم أساسية&quot;">​</a></h2><table tabindex="0"><thead><tr><th>المفهوم</th><th>الملخص</th></tr></thead><tbody><tr><td>الصلاحية (Permission)</td><td>صلاحية Spatie تتبع اصطلاح التسمية <code>group-action</code> (مثال: <code>orders-create</code>). تمنح قدرة (ability).</td></tr><tr><td>نطاق الدور (Role scope)</td><td>كل دور إما <code>global</code> (يُعيَّن مباشرة، وينطبق في كل مكان) أو <code>contextual</code> (مرتبط بأنواع نماذج محددة، ولا يمكن تعيينه إلا ضمن نسخة سياق).</td></tr><tr><td>الدور السقفي (Ceiling role)</td><td>يمكن لدور ما أن يعلن عن دور أب تُشكّل مجموعة صلاحياته حداً أعلى - لا يمكن للدور الفرعي أن يتجاوزه أبداً.</td></tr><tr><td>السياق (Context)</td><td>نسخة نموذج (متجر، مستأجر، مشروع) يمكن تقييد دور أو تجاوز صلاحية بها.</td></tr><tr><td>التجاوز (Override)</td><td>منح أو رفض صلاحية من نوع <code>forced_on</code>/<code>forced_off</code> خاص بكل مستخدم وكل سياق - الرفض يفوز دائماً.</td></tr></tbody></table><p>كل واحد من هذه المفاهيم له صفحة كاملة خاصة به: <a href="/clearance-docs/ar/features/permissions.html">الصلاحيات</a>، <a href="/clearance-docs/ar/features/roles.html">الأدوار</a>، <a href="/clearance-docs/ar/features/contextual-authorization.html">التفويض السياقي</a>، <a href="/clearance-docs/ar/features/users.html">المستخدمون</a>، <a href="/clearance-docs/ar/features/super-admin.html">المشرف الفائق</a>.</p><h2 id="الخطوات-التالية" tabindex="-1">الخطوات التالية <a class="header-anchor" href="#الخطوات-التالية" aria-label="Permalink to &quot;الخطوات التالية&quot;">​</a></h2><p>هل أنت مستعد لتثبيت Clearance؟ تابع إلى <a href="/clearance-docs/ar/guide/installation.html">دليل التثبيت</a>.</p>',14)])])}const m=t(d,[["render",i]]);export{p as __pageData,m as default};
